std::vector<
  std::unique_ptr<revm::Instruction>
> ConstructMatchesXsBooleanProgram() {
  std::vector<std::unique_ptr<revm::Instruction> > program;

  {  // ^(true|false|1|0)$
    {  // true|false|1|0
      program.emplace_back(
        common::make_unique<revm::InstructionSplit>(1, 6)
      );
      {  // true
        // t
        program.emplace_back(  // 1
          common::make_unique<revm::InstructionChar>(L't')
        );
        // r
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L'r')
        );
        // u
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L'u')
        );
        // e
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L'e')
        );
      }  // true
      program.emplace_back(
        common::make_unique<revm::InstructionJump>(17)
      );
      program.emplace_back(  // 6
        common::make_unique<revm::InstructionSplit>(7, 13)
      );
      {  // false
        // f
        program.emplace_back(  // 7
          common::make_unique<revm::InstructionChar>(L'f')
        );
        // a
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L'a')
        );
        // l
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L'l')
        );
        // s
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L's')
        );
        // e
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L'e')
        );
      }  // false
      program.emplace_back(
        common::make_unique<revm::InstructionJump>(17)
      );
      program.emplace_back(  // 13
        common::make_unique<revm::InstructionSplit>(14, 16)
      );
      // 1
      program.emplace_back(  // 14
        common::make_unique<revm::InstructionChar>(L'1')
      );
      program.emplace_back(
        common::make_unique<revm::InstructionJump>(17)
      );
      // 0
      program.emplace_back(  // 16
        common::make_unique<revm::InstructionChar>(L'0')
      );
    }  // true|false|1|0
    // $
    program.emplace_back(  // 17
      common::make_unique<revm::InstructionEnd>()
    );
    program.emplace_back(
      common::make_unique<revm::InstructionMatch>()
    );
  }  // ^(true|false|1|0)$

  return program;
}

