std::vector<
  std::unique_ptr<revm::Instruction>
> ConstructMatchesXsNonPositiveIntegerProgram() {
  std::vector<std::unique_ptr<revm::Instruction> > program;

  {  // ^(\+0|0|-[0-9]+)$
    {  // \+0|0|-[0-9]+
      program.emplace_back(
        common::make_unique<revm::InstructionSplit>(1, 4)
      );
      {  // \+0
        // \+
        program.emplace_back(  // 1
          common::make_unique<revm::InstructionChar>(L'+')
        );
        // 0
        program.emplace_back(
          common::make_unique<revm::InstructionChar>(L'0')
        );
      }  // \+0
      program.emplace_back(
        common::make_unique<revm::InstructionJump>(10)
      );
      program.emplace_back(  // 4
        common::make_unique<revm::InstructionSplit>(5, 7)
      );
      // 0
      program.emplace_back(  // 5
        common::make_unique<revm::InstructionChar>(L'0')
      );
      program.emplace_back(
        common::make_unique<revm::InstructionJump>(10)
      );
      {  // -[0-9]+
        // -
        program.emplace_back(  // 7
          common::make_unique<revm::InstructionChar>(L'-')
        );
        {  // [0-9]+
          // [0-9]
          program.emplace_back(  // 8
            common::make_unique<revm::InstructionSet>(
              std::vector<revm::Range>{
                revm::Range(L'0', L'9')
              }
            )
          );
          program.emplace_back(
            common::make_unique<revm::InstructionSplit>(8, 10)
          );
        }  // [0-9]+
      }  // -[0-9]+
    }  // \+0|0|-[0-9]+
    // $
    program.emplace_back(  // 10
      common::make_unique<revm::InstructionEnd>()
    );
    program.emplace_back(
      common::make_unique<revm::InstructionMatch>()
    );
  }  // ^(\+0|0|-[0-9]+)$

  return program;
}

